document.addEventListener('DOMContentLoaded', () => {
    const sleepEl = document.getElementById('bio-sleep');
    const hrvEl = document.getElementById('bio-hrv');
    const focusEl = document.getElementById('bio-focus');
    const chartContainer = document.getElementById('bio-chart');

    async function fetchBiometrics() {
        try {
            // Path to the data file generated by GitHub Action
            const response = await fetch('/data/biometrics.json');
            if (!response.ok) throw new Error('Data not available');

            const data = await response.json();
            updateUI(data);
        } catch (error) {
            console.warn('Biometrics data could not be loaded. Showing fallback data.');
            showFallback();
        }
    }

    function updateUI(data) {
        // Update main stats
        if (data.latest) {
            if (sleepEl) sleepEl.innerText = `${data.latest.sleep} HRS`;
            if (hrvEl) hrvEl.innerText = `${data.latest.hrv} MS`;
            if (focusEl) focusEl.innerText = `${data.latest.focus} %`;
        }

        // Update chart
        if (data.history && chartContainer) {
            chartContainer.innerHTML = '';
            // Assuming history is an array of percentages or values
            data.history.forEach(val => {
                const bar = document.createElement('div');
                bar.className = 'bar';
                bar.style.height = `${val}%`;
                chartContainer.appendChild(bar);
            });
        }
    }

    function showFallback() {
        if (sleepEl) sleepEl.innerText = '7.2 HRS';
        if (hrvEl) hrvEl.innerText = '64 MS';
        if (focusEl) focusEl.innerText = '85 %';

        if (chartContainer) {
            chartContainer.innerHTML = '';
            const fallbacks = [40, 60, 50, 80, 70, 90, 65, 85, 55, 45, 70, 80, 60];
            fallbacks.forEach(val => {
                const bar = document.createElement('div');
                bar.className = 'bar';
                bar.style.height = `${val}%`;
                chartContainer.appendChild(bar);
            });
        }
    }

    fetchBiometrics();
});
